<template>
    <div>
         <nav class="navbar navbar-expand-md navbar-dark bg-dark fixed-top">
             <router-link v-bind:to="{ name: 'Home' }" class="navbar-brand">Home</router-link>
             <button id="navButton" class="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarsExampleDefault" aria-controls="navbarsExampleDefault" aria-expanded="false" aria-label="Toggle navigation">
                 <span class="navbar-toggler-icon"></span>
             </button>
             <div class="collapse navbar-collapse" id="navbarsExampleDefault">
                 <ul class="navbar-nav mr-auto">
                     <li class="nav-item active">
                         <router-link v-bind:to="{ name: 'Home' }" class="nav-link">
                             Home<span class="sr-only">(current)</span>
                         </router-link>
                     </li>
                     <li class="nav-item active">
                         <router-link v-bind:to="{ name: 'Hello' }" class="nav-link">
                             Hello
                         </router-link>
                     </li>
                     <li class="nav-item active">
                         <router-link v-bind:to="{ name: 'TodoPage' }" class="nav-link">
                             TodoPage
                         </router-link>
                     </li>
                     <li class="nav-item active">
                         <router-link v-bind:to="{ name: 'Map' }" class="nav-link">
                             Map
                         </router-link>
                     </li>
                     <li class="nav-item">
                         <a class="nav-link disabled" href="javascript:void(0);">Disabled</a>
                     </li>
                     <li class="nav-item dropdown">
                         <a class="nav-link dropdown-toggle" href="http://example.com" id="dropdown01" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false">Dropdown</a>
                         <div class="dropdown-menu" aria-labelledby="dropdown01">
                             <a class="dropdown-item" href="javascript:void(0);">Action</a>
                             <a class="dropdown-item" href="javascript:void(0);">Another action</a>
                             <a class="dropdown-item" href="javascript:void(0);">Something else here</a>
                         </div>
                     </li>
                 </ul>
                 <form class="form-inline my-2 my-lg-0">
                     <input class="form-control mr-sm-2" type="text" placeholder="Search" aria-label="Search">
                     <button class="btn btn-outline-success my-2 my-sm-0" type="submit">Search</button>
                 </form>
             </div>
         </nav>

         <main role="main" class="container">
             <div class="starter-template">
                 <router-view></router-view>
             </div>
         </main>
     </div>
</template>

<script>
    export default {
        name: "Index",
        beforeCreate() {
            //  가장 먼저 실행되는 훅
            //  data와 event가 세팅되지 않는시점
        },
        created() {
            //  data와 events가 활성화되어 접근가능
            //  템플릿과 가상돔은 마운트 및 렌더링 되지 않은 상태
        },
        beforeMount() {
            //  첫 렌더링이 일어나기 직전에 실행됨.
            //  사용 권장x
        },
        mounted() {
            let el = {
                $navLink: $(".nav-link"),
                $navButton: $("#navButton")
            };
            el.$navLink.on("click", () => {
                console.log("movePage!!");
                el.$navButton.trigger("click");
            });
            //  컴포넌트, 템플릿, 렌더링된 돔에 접근할 수 있다.
        },
        beforeUpdate() {
            //  포넌트의 데이터가 변하여 업데이트 사이클이 시작될때 실행된다.
            //  정확히는 돔이 재 렌더링되고 패치되기 직전에 실행된다.
            //  재 렌더링 전의 새 상태의 데이터를 얻을 수 있고 더 많은 변경이 가능하다.
        },
        updated() {
            //  재 렌더링이 일어나 후에 실행된다.
            //  돔이 업데이트 완료된 상태이므로 돔 종속적인 연산을 할 수 있다.
            //  그러나 여기서 상태를 변경하면 무한루프에 빠질 수 있다.
        },
        init() {
        },
        directives: {},
        components: {},
        filters: {}
    }
</script>

<style scoped>
    body {
        padding-top: 5rem;
    }
    .starter-template {
        padding: 5rem 1.5rem;
        text-align: center;
    }
</style>



