import Vue from 'vue';
import VueRouter from 'vue-router';

// 여기 밑으로 뷰 컴포넌트 추가.
import Index from "../components/Index";

Vue.use(VueRouter);

const Map = () => import(/* webpackChunkName: "Map" */'../components/Map');
const Home = () => import(/* webpackChunkName: "Home" */'../components/Home');
const Hello = () => import(/* webpackChunkName: "Hello" */'../components/Hello');
const TodoPage = () => import(/* webpackChunkName: "TodoPage" */'../components/Todo/TodoPage');

export default new VueRouter({
    mode: 'history',
    routes: [
        {
            path: '/',
            name: 'Index',
            component: Index,
            children: [
                {   path: '/',
                    name: 'Home',
                    component: Home
                },
                {
                    path: '/Hello',
                    name: 'Hello',
                    component: Hello
                },
                {
                    path: '/Map',
                    name: 'Map',
                    component: Map
                },
                {
                    path: 'TodoPage',
                    name: 'TodoPage',
                    component: TodoPage
                },
            ]
        }
    ]
})



